import{_ as a,c as l,o as i,ah as r}from"./chunks/framework.MIBBae6R.js";const p=JSON.parse('{"title":"{Shimera} Architecture Technique Actuelle","description":"","frontmatter":{},"headers":[],"relativePath":"fr/devdoc/architecture/technical_architecture.md","filePath":"fr/devdoc/architecture/technical_architecture.md"}'),t={name:"fr/devdoc/architecture/technical_architecture.md"};function s(d,e,c,n,o,u){return i(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="shimera-architecture-technique-actuelle" tabindex="-1"><strong>{Shimera} Architecture Technique Actuelle</strong> <a class="header-anchor" href="#shimera-architecture-technique-actuelle" aria-label="Permalink to “{Shimera} Architecture Technique Actuelle”">​</a></h1><blockquote><p>Une vue factuelle de l&#39;architecture de Shimera, au niveau implémentation, basée sur l&#39;état actuel du code.</p></blockquote><h2 id="sommaire" tabindex="-1">Sommaire <a class="header-anchor" href="#sommaire" aria-label="Permalink to “Sommaire”">​</a></h2><ol><li><a href="#vue-densemble-de-larchitecture">Vue d&#39;ensemble de l&#39;architecture</a></li><li><a href="#modules-coeur">Modules coeur</a></li><li><a href="#pipeline-de-rendu">Pipeline de rendu</a></li><li><a href="#dependances">Dépendances</a></li><li><a href="#flux-de-donnees-internes">Flux de données internes</a></li><li><a href="#systeme-de-build">Système de build</a></li><li><a href="#strategie-de-versioning">Stratégie de versioning</a></li><li><a href="#contraintes-actuelles">Contraintes actuelles</a></li><li><a href="#references">Références</a></li></ol><h2 id="vue-d-ensemble-de-l-architecture" tabindex="-1">Vue d&#39;ensemble de l&#39;architecture <a class="header-anchor" href="#vue-d-ensemble-de-l-architecture" aria-label="Permalink to “Vue d&#39;ensemble de l&#39;architecture”">​</a></h2><p>Shimera utilise une abstraction de backend pour exécuter le même workflow de post-processing sur plusieurs écosystèmes.</p><p>L&#39;architecture suit ce modèle en couches:</p><ol><li>Couche API publique et ABI (<code>shimera.h</code>, <code>shimera_api.h</code>).</li><li>Couche d&#39;abstraction backend (<code>IBackend</code>, interfaces de ressources, <code>BackendFactory</code>).</li><li>Adaptateurs backend concrets (OpenGL, SFML, Raylib, placeholder SDL).</li><li>Couche framework d&#39;effets (<code>ShaderEffectBase</code>, CRTP <code>ShaderEffect&lt;Derived&gt;</code>).</li><li>Couche de support partagée (valeurs d&#39;uniformes, types vecteurs légers, utilitaires GL).</li></ol><p>Le choix du backend se fait à la compilation (cible de build + define préprocesseur), et non via un système plugin au runtime.</p><h2 id="modules-coeur" tabindex="-1">Modules coeur <a class="header-anchor" href="#modules-coeur" aria-label="Permalink to “Modules coeur”">​</a></h2><h3 id="surface-d-api-publique" tabindex="-1">Surface d&#39;API publique <a class="header-anchor" href="#surface-d-api-publique" aria-label="Permalink to “Surface d&#39;API publique”">​</a></h3><p>Points d&#39;entrée principaux:</p><ul><li><code>include/shimera.h</code></li><li><code>include/shimera_api.h</code></li></ul><p>Responsabilités:</p><ul><li>Fournir un point d&#39;inclusion public compact.</li><li>Gérer l&#39;export/import des symboles pour les builds statiques ou partagés.</li></ul><h3 id="couche-d-abstraction-backend" tabindex="-1">Couche d&#39;abstraction backend <a class="header-anchor" href="#couche-d-abstraction-backend" aria-label="Permalink to “Couche d&#39;abstraction backend”">​</a></h3><p>Fichiers clés:</p><ul><li><code>include/backend/IBackend.hpp</code></li><li><code>include/backend/BackendFactory.hpp</code></li><li><code>src/backend/BackendFactory.cpp</code></li></ul><p>Responsabilités:</p><ul><li>Définir des contrats abstraits de création pour framebuffers, textures, shaders et post-processors.</li><li>Masquer les implémentations concrètes derrière des interfaces.</li><li>Sélectionner l&#39;implémentation via un macro backend: <ul><li><code>SHIMERA_BACKEND_OPENGL</code></li><li><code>SHIMERA_BACKEND_SFML</code></li><li><code>SHIMERA_BACKEND_RAYLIB</code></li><li><code>SHIMERA_BACKEND_SDL</code> (actuellement un chemin placeholder)</li></ul></li></ul><h3 id="interfaces-de-ressources" tabindex="-1">Interfaces de ressources <a class="header-anchor" href="#interfaces-de-ressources" aria-label="Permalink to “Interfaces de ressources”">​</a></h3><ul><li><code>IFrameBuffer</code>: cycle de vie du render target, redimensionnement, accès texture.</li><li><code>IPostProcessor</code>: orchestration des passes de post-processing fullscreen.</li><li><code>IShader</code>: bind/unbind shader et écriture d&#39;uniformes typées.</li><li><code>ITexture</code>: bind/unbind texture et pont vers handle natif.</li></ul><h3 id="backends-concrets" tabindex="-1">Backends concrets <a class="header-anchor" href="#backends-concrets" aria-label="Permalink to “Backends concrets”">​</a></h3><ol><li>Backend OpenGL (<code>src/backend/opengl/*</code>)</li></ol><ul><li>Possession native des ressources GL pour framebuffers, textures, shaders et passes fullscreen.</li></ul><ol start="2"><li>Backend SFML (<code>src/backend/sfml/*</code>)</li></ol><ul><li>Capture de scène via <code>sf::RenderTexture</code>.</li><li>Post-processing toujours exécuté via une passe fullscreen basée OpenGL.</li></ul><ol start="3"><li>Backend Raylib (<code>src/backend/raylib/*</code>)</li></ol><ul><li>Capture de scène via <code>RenderTexture2D</code>.</li><li>Post-processing toujours exécuté via une passe fullscreen basée OpenGL.</li></ul><ol start="4"><li>Backend SDL</li></ol><ul><li>La cible de build et le macro existent.</li><li>Le chemin factory est un placeholder et n&#39;instancie pas de backend concret.</li></ul><h3 id="framework-d-effets" tabindex="-1">Framework d&#39;effets <a class="header-anchor" href="#framework-d-effets" aria-label="Permalink to “Framework d&#39;effets”">​</a></h3><p>Fichiers clés:</p><ul><li><code>include/effects/ShaderEffectBase.hpp</code></li><li><code>include/effects/ShaderEffect.inl</code></li><li><code>src/effects/*.cpp</code></li></ul><p>Design:</p><ul><li>Classes d&#39;effets stateful, chacune encapsulant un post-processor.</li><li>API fluide basée sur le CRTP (<code>ShaderEffect&lt;Derived&gt;</code>).</li><li>Pattern d&#39;exécution commun: <ul><li><code>render(texture)</code></li><li><code>render(texture, framebuffer)</code></li></ul></li></ul><p>Effets intégrés dans l&#39;état actuel du code:</p><ul><li>Brightness</li><li>Contrast</li><li>Saturation</li><li>Grayscale</li><li>Colorshift</li><li>Distortion</li><li>Vignette</li><li>Chromatic Aberration</li></ul><h2 id="pipeline-de-rendu" tabindex="-1">Pipeline de rendu <a class="header-anchor" href="#pipeline-de-rendu" aria-label="Permalink to “Pipeline de rendu”">​</a></h2><p>Le pipeline runtime est orienté passes et utilise des framebuffers offscreen.</p><h3 id="etape-1-capture-de-scene" tabindex="-1">Etape 1: Capture de scène <a class="header-anchor" href="#etape-1-capture-de-scene" aria-label="Permalink to “Etape 1: Capture de scène”">​</a></h3><ol><li>Binder le framebuffer A.</li><li>Rendre les draw calls de la scène/application.</li><li>Unbinder le framebuffer A.</li></ol><h3 id="etape-2-passe-de-post-processing" tabindex="-1">Etape 2: Passe de post-processing <a class="header-anchor" href="#etape-2-passe-de-post-processing" aria-label="Permalink to “Etape 2: Passe de post-processing”">​</a></h3><ol><li>Lire la texture du framebuffer précédent.</li><li>Mettre à jour les uniformes d&#39;effet.</li><li>Dessiner un quad fullscreen avec la passe shader.</li></ol><h3 id="etape-3-presentation" tabindex="-1">Etape 3: Présentation <a class="header-anchor" href="#etape-3-presentation" aria-label="Permalink to “Etape 3: Présentation”">​</a></h3><ul><li>La sortie va soit vers l&#39;écran, soit vers un autre framebuffer.</li><li>Cela permet de chaîner plusieurs passes (ping-pong).</li></ul><h3 id="contrat-commun-des-passes-shader" tabindex="-1">Contrat commun des passes shader <a class="header-anchor" href="#contrat-commun-des-passes-shader" aria-label="Permalink to “Contrat commun des passes shader”">​</a></h3><ul><li>La passe vertex consomme des positions fullscreen + UV.</li><li>La passe fragment échantillonne <code>u_screenTexture</code> (texture unit 0) et applique les uniformes d&#39;effet.</li></ul><h3 id="flux-typiques" tabindex="-1">Flux typiques <a class="header-anchor" href="#flux-typiques" aria-label="Permalink to “Flux typiques”">​</a></h3><p>Single-pass:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Scene -&gt; Framebuffer A -&gt; Effect Pass -&gt; Screen</span></span></code></pre></div><p>Two-pass ping-pong:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Scene -&gt; Framebuffer A -&gt; Effect 1 -&gt; Framebuffer B -&gt; Effect 2 -&gt; Screen</span></span></code></pre></div><h2 id="dependances" tabindex="-1">Dépendances <a class="header-anchor" href="#dependances" aria-label="Permalink to “Dépendances”">​</a></h2><p>Les dépendances de Shimera sont organisées par cible backend dans Xmake.</p><h3 id="packages-declares-au-build" tabindex="-1">Packages déclarés au build <a class="header-anchor" href="#packages-declares-au-build" aria-label="Permalink to “Packages déclarés au build”">​</a></h3><ul><li><code>glew</code></li><li><code>sfml</code> (optionnel)</li><li><code>raylib</code> (optionnel)</li><li><code>libsdl3</code> (optionnel)</li></ul><h3 id="matrice-des-cibles-backend" tabindex="-1">Matrice des cibles backend <a class="header-anchor" href="#matrice-des-cibles-backend" aria-label="Permalink to “Matrice des cibles backend”">​</a></h3><table tabindex="0"><thead><tr><th>Target</th><th>Define</th><th>Packages</th><th>Status</th></tr></thead><tbody><tr><td><code>shimera-opengl</code></td><td><code>SHIMERA_BACKEND_OPENGL</code></td><td><code>glew</code></td><td>Implémenté</td></tr><tr><td><code>shimera-sfml</code></td><td><code>SHIMERA_BACKEND_SFML</code></td><td><code>glew</code>, <code>sfml</code></td><td>Implémenté</td></tr><tr><td><code>shimera-raylib</code></td><td><code>SHIMERA_BACKEND_RAYLIB</code></td><td><code>glew</code>, <code>raylib</code></td><td>Implémenté</td></tr><tr><td><code>shimera-sdl</code></td><td><code>SHIMERA_BACKEND_SDL</code></td><td><code>glew</code>, <code>libsdl3</code></td><td>Chemin de build existe, mais backend incomplet</td></tr></tbody></table><h3 id="opengl-et-glew-dans-l-architecture-actuelle" tabindex="-1">OpenGL et GLEW dans l&#39;architecture actuelle <a class="header-anchor" href="#opengl-et-glew-dans-l-architecture-actuelle" aria-label="Permalink to “OpenGL et GLEW dans l&#39;architecture actuelle”">​</a></h3><p>Même avec les variantes backend SFML ou Raylib, l&#39;exécution du post-processing reste basée sur OpenGL.</p><p>Conséquence pratique:</p><ul><li>GLEW et les librairies système OpenGL restent des dépendances fondamentales pour toutes les variantes backend actuelles.</li></ul><h2 id="flux-de-donnees-internes" tabindex="-1">Flux de données internes <a class="header-anchor" href="#flux-de-donnees-internes" aria-label="Permalink to “Flux de données internes”">​</a></h2><p>Le comportement de Shimera peut être lu à travers 5 flux principaux.</p><h3 id="_1-flux-de-controle" tabindex="-1">1) Flux de contrôle <a class="header-anchor" href="#_1-flux-de-controle" aria-label="Permalink to “1) Flux de contrôle”">​</a></h3><ul><li>L&#39;application initialise la stack contexte/fenêtre.</li><li>L&#39;application crée le backend (<code>BackendFactory::create</code>).</li><li>L&#39;application crée les framebuffers et les effets.</li><li>A chaque frame: capture de scène -&gt; chaînage de passes -&gt; présentation.</li></ul><h3 id="_2-flux-render-target" tabindex="-1">2) Flux render-target <a class="header-anchor" href="#_2-flux-render-target" aria-label="Permalink to “2) Flux render-target”">​</a></h3><ul><li><code>IFrameBuffer::bind/unbind</code> redirige la sortie de rendu vers la cible sélectionnée.</li><li>La sémantique varie selon le backend (OpenGL FBO, SFML render texture, Raylib texture mode).</li></ul><h3 id="_3-flux-texture" tabindex="-1">3) Flux texture <a class="header-anchor" href="#_3-flux-texture" aria-label="Permalink to “3) Flux texture”">​</a></h3><ul><li>La sortie framebuffer est exposée en <code>ITexture</code>.</li><li>Les post-processors consomment cette texture en entrée de passe.</li><li>La sortie d&#39;une passe devient l&#39;entrée de la suivante.</li></ul><h3 id="_4-flux-uniforms" tabindex="-1">4) Flux uniforms <a class="header-anchor" href="#_4-flux-uniforms" aria-label="Permalink to “4) Flux uniforms”">​</a></h3><ul><li>Les champs des effets sont poussés à chaque render call via <code>setUniform</code>.</li><li>Les valeurs passent par <code>UniformValue</code> puis le dispatch shader backend.</li><li>Les classes shader mettent en cache les locations d&#39;uniformes pour réduire les lookups répétés.</li></ul><h3 id="_5-flux-de-cycle-de-vie" tabindex="-1">5) Flux de cycle de vie <a class="header-anchor" href="#_5-flux-de-cycle-de-vie" aria-label="Permalink to “5) Flux de cycle de vie”">​</a></h3><ul><li>Les effets possèdent les processors.</li><li>Les processors possèdent les objets shader.</li><li>Les framebuffers possèdent les wrappers de texture.</li><li>La libération des ressources suit la hiérarchie des objets.</li></ul><h2 id="systeme-de-build" tabindex="-1">Système de build <a class="header-anchor" href="#systeme-de-build" aria-label="Permalink to “Système de build”">​</a></h2><p>Shimera utilise Xmake (<code>xmake.lua</code>) avec une stratégie une cible par backend.</p><h3 id="parametres-globaux-de-build" tabindex="-1">Paramètres globaux de build <a class="header-anchor" href="#parametres-globaux-de-build" aria-label="Permalink to “Paramètres globaux de build”">​</a></h3><ul><li>Modes de build: debug/release.</li><li>Standard C++: C++23.</li><li>Politique toolchain sous Windows: MSVC.</li></ul><h3 id="options-top-level" tabindex="-1">Options top-level <a class="header-anchor" href="#options-top-level" aria-label="Permalink to “Options top-level”">​</a></h3><ul><li><code>shared</code> (défaut: false): build shared ou static.</li><li><code>examples</code> (défaut: true): inclure les applications d&#39;exemple.</li></ul><h3 id="sous-systeme-d-exemples" tabindex="-1">Sous-système d&#39;exemples <a class="header-anchor" href="#sous-systeme-d-exemples" aria-label="Permalink to “Sous-système d&#39;exemples”">​</a></h3><p>Quand activé, des cibles d&#39;exemple sont incluses pour OpenGL, SFML, Raylib et SDL. Chaque exemple dépend de la cible backend correspondante.</p><h3 id="politique-de-linkage-plateforme" tabindex="-1">Politique de linkage plateforme <a class="header-anchor" href="#politique-de-linkage-plateforme" aria-label="Permalink to “Politique de linkage plateforme”">​</a></h3><p>Les librairies système OpenGL sont liées selon la plateforme:</p><ul><li>Windows: <code>opengl32</code></li><li>macOS: framework <code>OpenGL</code></li><li>Linux/Unix-like: <code>GL</code></li></ul><h2 id="strategie-de-versioning" tabindex="-1">Stratégie de versioning <a class="header-anchor" href="#strategie-de-versioning" aria-label="Permalink to “Stratégie de versioning”">​</a></h2><p>Le workflow actuel combine intégration par branches et releases par tags.</p><h3 id="modele-de-branches" tabindex="-1">Modèle de branches <a class="header-anchor" href="#modele-de-branches" aria-label="Permalink to “Modèle de branches”">​</a></h3><p>Branches longue durée:</p><ul><li><code>dev</code> (branche d&#39;intégration active)</li><li><code>master</code> (branche orientée stabilité)</li></ul><p>Nommage fréquent des branches courtes:</p><ul><li><code>feat/*</code></li><li><code>fix/*</code></li><li><code>chore/*</code></li></ul><h3 id="style-de-commits-et-merges" tabindex="-1">Style de commits et merges <a class="header-anchor" href="#style-de-commits-et-merges" aria-label="Permalink to “Style de commits et merges”">​</a></h3><ul><li>Les merge commits de PR sont conservés dans l&#39;historique.</li><li>Les préfixes de type Conventional sont fréquents (<code>feat</code>, <code>fix</code>, <code>docs</code>, <code>ci</code>, <code>build</code>, etc.), mais non strictement uniformes.</li></ul><h3 id="declenchement-ci-cd-du-versioning" tabindex="-1">Déclenchement CI/CD du versioning <a class="header-anchor" href="#declenchement-ci-cd-du-versioning" aria-label="Permalink to “Déclenchement CI/CD du versioning”">​</a></h3><ul><li>La CI tourne sur push/PR pour les branches de travail principales.</li><li>Le workflow de release est déclenché par tags <code>v*</code>.</li><li>Le statut prerelease est déduit si le tag contient <code>-</code> (par exemple <code>v1.2.0-rc1</code>).</li><li>Les artefacts de release incluent la plateforme et la version dans le nom de fichier.</li></ul><h2 id="contraintes-actuelles" tabindex="-1">Contraintes actuelles <a class="header-anchor" href="#contraintes-actuelles" aria-label="Permalink to “Contraintes actuelles”">​</a></h2><p>L&#39;implémentation actuelle a des contraintes importantes pour la roadmap:</p><ol><li>Le chemin backend SDL n&#39;est pas complètement implémenté.</li><li><code>SFMLBackend::createTexture</code> et <code>RaylibBackend::createTexture</code> sont incomplets.</li><li>La logique post-processor/shader est dupliquée entre les implémentations backend.</li><li>Les chemins shaders des effets sont hardcodés en relatif dans les constructeurs.</li></ol><p>Ces contraintes n&#39;invalident pas le pattern architectural, mais elles impactent la maintenabilité et la robustesse du packaging.</p><h2 id="references" tabindex="-1">Références <a class="header-anchor" href="#references" aria-label="Permalink to “Références”">​</a></h2><ul><li><a href="https://fr.wikipedia.org/wiki/Application_binary_interface" target="_blank" rel="noreferrer">Interface binaire-programme (ABI)</a></li><li><a href="https://en.wikipedia.org/wiki/Curiously_recurring_template_pattern" target="_blank" rel="noreferrer">Curiously recurring template pattern (CRTP)</a></li><li><a href="https://xmake.io/#/guide/basic_commands" target="_blank" rel="noreferrer">Xmake Manual</a></li><li><a href="https://www.conventionalcommits.org/en/v1.0.0/" target="_blank" rel="noreferrer">Conventional Commits</a></li></ul>',103)])])}const m=a(t,[["render",s]]);export{p as __pageData,m as default};
